package main

import (
	"encoding/json"
	"errors"
	"os"
	"sort"
)

type entry struct {
	Case      string `json:"case"`
	Produced  []int  `json:"produced"`
	Trace     []int  `json:"slot_trace"`
	OrderUsed []int  `json:"order_used"`
	Packed    bool   `json:"packed"`
	Grouped   bool   `json:"grouped"`
	Reuse     bool   `json:"reuse"`
}

type rawDoc struct {
	Raw []entry `json:"raw"`
}

type finalDoc struct {
	Rows    []entry        `json:"rows"`
	Summary map[string]any `json:"summary"`
}

func toMap(rows []entry) (map[string]entry, error) {
	m := make(map[string]entry, len(rows))
	for _, r := range rows {
		if r.Case == "" {
			return nil, errors.New("row missing case name")
		}
		if _, ok := m[r.Case]; ok {
			return nil, errors.New("duplicate case in rows: " + r.Case)
		}
		m[r.Case] = r
	}
	return m, nil
}

func equalInts(a, b []int) bool {
	if len(a) != len(b) {
		return false
	}
	for i := range a {
		if a[i] != b[i] {
			return false
		}
	}
	return true
}

// matchesSpec checks equality across the six required fields.
func matchesSpec(a, b entry) bool {
	return a.Case == b.Case &&
		equalInts(a.Produced, b.Produced) &&
		equalInts(a.Trace, b.Trace) &&
		equalInts(a.OrderUsed, b.OrderUsed) &&
		a.Packed == b.Packed &&
		a.Grouped == b.Grouped &&
		a.Reuse == b.Reuse
}

func sortedCases(m map[string]entry) []string {
	cases := make([]string, 0, len(m))
	for k := range m {
		cases = append(cases, k)
	}
	sort.Strings(cases)
	return cases
}

func main() {
	if len(os.Args) != 3 {
		panic("usage: align raw final")
	}

	buf, err := os.ReadFile(os.Args[1])
	if err != nil {
		panic(err)
	}
	var raw rawDoc
	if err := json.Unmarshal(buf, &raw); err != nil {
		panic(err)
	}

	// Collation stage: keep exactly one row per case name; do not drop/merge.
	rawMap, err := toMap(raw.Raw)
	if err != nil {
		panic(err)
	}

	// Deterministic local report rows: stable ordering of the raw rows.
	cases := sortedCases(rawMap)
	rows := make([]entry, 0, len(cases))
	for _, c := range cases {
		rows = append(rows, rawMap[c])
	}

	// agree iff every report row matches its raw counterpart across the six required fields,
	// and overwriting an existing report.json only keeps agree=true if the prior report rows
	// also match the incoming raw rows across those same fields.
	agree := true

	repMap, err := toMap(rows)
	if err != nil {
		panic(err)
	}
	if len(repMap) != len(rawMap) {
		agree = false
	}
	for c, rr := range rawMap {
		fr, ok := repMap[c]
		if !ok || !matchesSpec(rr, fr) {
			agree = false
			break
		}
	}

	if prevBuf, err := os.ReadFile(os.Args[2]); err == nil {
		var prev finalDoc
		if err := json.Unmarshal(prevBuf, &prev); err == nil {
			prevMap, err := toMap(prev.Rows)
			if err != nil {
				agree = false
			} else {
				if len(prevMap) != len(rawMap) {
					agree = false
				}
				for c, rr := range rawMap {
					pr, ok := prevMap[c]
					if !ok || !matchesSpec(rr, pr) {
